    required String id,
    required String name,
    required String emoji,
    required Color background,
    required Color surface,
    required Color card,
    required Color primary,
    required Color secondary,
    required Color accent,
    required Color text,
    required Color textSecondary,
    required Color chatBubbleUser,
    required Color chatBubbleAI,
    required Color navbarBg,
    required LinearGradient primaryGradient,
    required LinearGradient backgroundGradient,
    required bool isLight,
    required bool isPremium,
    Color border = Colors.transparent,
    Color? inputFill,
    Color? inputBorder,
    Color? inputHint,
    Color? buttonText,
    Color? selectedTab,
    Color? unselectedTab,
    Color? glowColor,
  }) {
    return SineTheme(
      id: id,
      name: name,
      emoji: emoji,
      background: background,
      surface: surface,
      card: card,
      primary: primary,
      secondary: secondary,
      accent: accent,
      text: text,
      textSecondary: textSecondary,
      inputFill: inputFill ?? (isLight ? Colors.black.withValues(alpha: 0.05) : Colors.white.withValues(alpha: 0.05)),
      inputBorder: inputBorder ?? (isLight ? Colors.black.withValues(alpha: 0.1) : Colors.white.withValues(alpha: 0.1)),
      inputHint: inputHint ?? textSecondary.withValues(alpha: 0.5),
      buttonText: buttonText ?? (isLight ? Colors.white : Colors.black),
      selectedTab: selectedTab ?? primary,
      unselectedTab: unselectedTab ?? textSecondary.withValues(alpha: 0.5),
      chatBubbleUser: chatBubbleUser,
      chatBubbleAI: chatBubbleAI,
      navbarBg: navbarBg,
      border: border == Colors.transparent ? (isLight ? Colors.black.withValues(alpha: 0.05) : Colors.white.withValues(alpha: 0.05)) : border,
      glowColor: glowColor ?? primary.withValues(alpha: 0.2),
      primaryGradient: primaryGradient,
      backgroundGradient: backgroundGradient,
      isLight: isLight,
      isPremium: isPremium,
    );
  }

